/// <summary>
/// this class will create shipments for outbound orders
/// </summary>
public class ETGITMCreatorCreateShipmentOut implements SysPackable
{
    ITMTable shipTable;
    ITMContainers shipContainers;
    ITMFolioTable shipFolioTable;
    boolean headersCreated;

    NoYes createContainer;
    NoYes createFolio;
    NoYes findAutoCosts;

    ITMTmpCreatorLine tmpShipCreatorLine;
    ITMVesselId vesselId;
    ITMFromPort fromPort;
    ITMToPort toPort;
    DlvModeId dlvModeId;
    ITMVendAccount shipVendAccount;

    ITMContainerId containerId;
    ITMContainerTypeId containerTypeId;

    ITMCustomsBroker customsBroker;
    VendAccount vendAccount;

    Map companyFolioMap;
    ITMJourneyId journeyId;

    ITMId pendingShipment;
    ITMId pendingContainer;

    ITMDescription shipDescription;
    ITMId shipId;

    NoYes addToExistingContainer;
    NoYes addToExistingFolio;
    ITMFolioId folioId;

    ITMJourneyId containerJourneyId;
    ITMVoyage voyage;
    ITMDate shipDate;

    container selectedLinesMap;

    ITMJourneyLine shipJourneyLine;

    ITMMAWB shipMAWB;
    ITMHAWB shipHAWB;

    ITMMeasurement containerMeasurement;
    ITMMeasurementUnit containerMeasurementUnit;

    ITMIdExternal shipIdExternal;
    ITMFolioId manualFolioId;

    boolean skipUserInteraction;

    private const int CurrentVersion = 1;
    #localmacro.CurrentList
        createContainer,
        createFolio,
        findAutoCosts
    #endmacro

}

