protected void checkExistingAutoCosts()
{
    boolean doPrompt;

    shipTable = ITMTable::find(shipId);

    if (ITMCostTrans::existEstimatedOutETG(shipTable))
    {
        warning("@InboundTransportationManagement:UnreversedEstimatesExistTheReverseCostsFunctionShouldBeUsed");
        throw error("@SYS18447");
    }

    doPrompt = ITMCostTrans::existUninvoicedOutETG(shipTable);

    if (addToExistingContainer)
    {
        shipContainers = ITMContainers::find(shipId, containerId);
        if (ITMCostTrans::existEstimatedOutETG(shipContainers))
        {
            warning("@InboundTransportationManagement:UnreversedEstimatesExistTheReverseCostsFunctionShouldBeUsed");
            throw error("@SYS18447");
        }

        doPrompt = ITMCostTrans::existUninvoicedOutETG(shipContainers) || doPrompt;
    }

    if (addToExistingFolio)
    {
        shipFolioTable = ITMFolioTable::find(folioId);
        if (ITMCostTrans::existEstimatedOutETG(shipFolioTable))
        {
            warning("@InboundTransportationManagement:UnreversedEstimatesExistTheReverseCostsFunctionShouldBeUsed");
            throw error("@SYS18447");
        }

        doPrompt = ITMCostTrans::existUninvoicedOutETG(shipFolioTable) || doPrompt;
    }

    if (doPrompt)
    {
        findAutoCosts = ITMAutoCostSearch::promptInsertCheck(skipUserInteraction);
    }
}

private void copyLegs()
{
    while select shipJourneyLine
        index LineIdx
        where shipJourneyLine.JourneyId == (containerJourneyId ? containerJourneyId : journeyId)
    {
        this.createContainerLeg();
    }
}

private void createContainerLeg()
{
    ITMContainerLegTable shipContainerLegTable;

    shipContainerLegTable.clear();
    shipContainerLegTable.initFromShipContainersOutETG(shipContainers);
    shipContainerLegTable.initFromShipJourneyLineOutETG(shipJourneyLine);
    shipContainerLegTable.insert();

    shipContainers.initFromShipJourneyLine(shipJourneyLine);

    ITMContainerLegTable::copyActivitiesOutETG(shipContainers, shipContainerLegTable);
}

protected void createHeaders()
{
    this.createShipTable();

    if (addToExistingContainer)
    {
        shipContainers = ITMContainers::find(shipId, containerId);
    }
    else if (createContainer)
    {
        this.createShipContainers();
    }

    if (addToExistingFolio)
    {
        shipFolioTable = ITMFolioTable::find(folioId);
    }

    headersCreated = true;
}

protected void createShipContainers()
{
    ITMContainers  shipContainersUpd;

    if (shipId && ITMContainers::exist(shipId, containerId))
    {
        throw error(strFmt("@InboundTransportationManagement:ContainerValueAlreadyExistsOnShipment", containerId, shipId));
    }

    this.initShipContainer();

    if (shipContainers.validateWrite())
    {
        select firstOnly shipJourneyLine;
        if (shipJourneyLine == null)
        {
            shipContainers.insert();
        }
        else
        {
            this.copyLegs();

            shipContainers.insert(false);
        }
    }
    else
    {
        throw error("@SYS18447");
    }

    shipContainersUpd = ITMContainers::findRecId(shipContainers.RecId, true);
    if (shipContainersUpd)
    {
        shipContainersUpd.ShipDate = shipDate;
        shipContainersUpd.update();
        shipContainers = shipContainersUpd;
    }
}

protected void initShipContainer()
{
    shipContainers.clear();
    shipContainers.initValue();
    shipContainers.initFromShipTable(shipTable);
    shipContainers.ShipId = shipTable.ShipId;
    shipContainers.ShipContainerId = containerId;
    shipContainers.ShipContainerTypeId = containerTypeId;
    shipContainers.ShipHAWB = shipHAWB;
    shipContainers.ShipMeasurement = containerMeasurement;
    shipContainers.ShipMeasurementUnit = containerMeasurementUnit;

    if (containerJourneyId)
    {
        shipContainers.ShipJourneyId = containerJourneyId;
    }
}

protected void createShipFolio()
{
    ITMTmpCreatorLine  tmpShipCreatorLineLocal;

    tmpShipCreatorLineLocal.setTmpData(tmpShipCreatorLine);
    companyFolioMap = new Map(Types::String, Types::String);

    while select ShipDataArea from tmpShipCreatorLineLocal
        group by ShipDataArea
    {
        shipFolioTable.clear();
        shipFolioTable.initValue();
        shipFolioTable.initFromShipTable(shipTable);
        shipFolioTable.ShipId = shipTable.ShipId;
        shipFolioTable.ShipFolioId = manualFolioId != '' ? manualFolioId : NumberSeq::newGetNum(ITMParameters::numRefShipFolioIdOutETG(), false).num();
        shipFolioTable.ShipCustomsBroker = customsBroker;
        shipFolioTable.VendAccount = vendAccount;
        shipFolioTable.ShipDataArea = tmpShipCreatorLineLocal.ShipDataArea;

        companyFolioMap.insert(shipFolioTable.ShipDataArea, shipFolioTable.ShipFolioId);

        if (shipFolioTable.validateWrite())
        {
            shipFolioTable.insert();
        }
        else
        {
            throw error("@SYS18447");
        }
    }
}

protected int createShipLine(ITMTmpCreatorLine _tmpShipCreatorLine)
{
    ITMFolioId shipFolioId;

    if (addToExistingFolio)
    {
        shipFolioId = shipFolioTable.ShipFolioId;
    }
    else
    {
        shipFolioId = this.findOrCreateFolio(_tmpShipCreatorLine.InventTransType, _tmpShipCreatorLine.InventTransId);
    }

    ITMLineCreate::newCreateLine(
        shipTable.ShipId,
        shipContainers.ShipContainerId,
        shipFolioId,
        _tmpShipCreatorLine.InventTransId,
        _tmpShipCreatorLine.InventTransType,
        _tmpShipCreatorLine.TransferQty,
        _tmpShipCreatorLine.Close);

    return 1;
}

protected void createShipTable()
{
    if (shipId)
    {
        shipTable = ITMTable::find(shipId);
        if (!shipTable)
        {
            throw error(strFmt("@InboundTransportationManagement:ShipmentValueDoesNotExistDot", shipId));
        }
        return;
    }

    this.initShipTable();

    if (shipTable.validateWrite())
    {
        shipTable.insert();
    }
    else
    {
        throw error("@SYS18447");
    }
}

protected void initShipTable()
{
    shipTable.clear();
    shipTable.initValue();
    shipTable.ShipId = this.getShipId();
    shipTable.ShipVesselId = vesselId;
    shipTable.ShipVoyage = voyage;
    shipTable.ShipFromPort = fromPort;
    shipTable.ShipToPort = toPort;
    shipTable.DlvModeId = dlvModeId;
    shipTable.ShipVendAccount = shipVendAccount;
    shipTable.ShipJourneyId = journeyId;
    shipTable.ShipDescription = shipDescription;
    shipTable.ShipMAWB = shipMAWB;
    shipTable.ShipIdExternal = shipIdExternal;
    shipTable.ETGLandedCostType = ETGLandedCostType::Outbound;
    if (journeyId)
    {
        shipTable.initPortsFromJourney();
    }
}

public ITMId getShipId()
{
    return NumberSeq::newGetNum(ITMParameters::numRefShipId(), false).num();
}

protected void findAutoCosts()
{
    MapEnumerator   mE = companyFolioMap.getEnumerator();

    shipTable.createShipCostTrans(true, true);

    if (createContainer || addToExistingContainer)
    {
        shipContainers.createShipCostTrans(true, true);
    }
    if (createFolio && !addToExistingFolio)
    {
        while (mE.moveNext())
        {
            shipFolioTable = ITMFolioTable::find(mE.currentValue());
            shipFolioTable.createShipCostTrans(true, true);
        }
    }
    else if (addToExistingFolio)
    {
        shipFolioTable.createShipCostTrans(true, true);
    }
}

protected ITMFolioId findOrCreateFolio(
    InventTransType _transType,
    InventTransId _inventTransId
    )
{
    ITMCreatorSetupTable shipCreatorSetupTable;
    SalesTable salesTable;
    InventDim inventDim;
    str keyStr;
    container mapKey;
    SalesLine salesLine;
    InventTransferLine inventTransferLine;
    InventTransferTable inventTransferTable;
    DataAreaId dataAreaId;
    ITMFolioId shipFolioId;

    Query query;
    QueryBuildDataSource qbds;
    QueryRun queryRun;

    if (createFolio)
    {
        select firstonly RecId from shipCreatorSetupTable;

        if (shipCreatorSetupTable.RecId)
        {
            query = new Query();
            qbds = query.addDataSource(tableNum(ITMCreatorSetupTable));
            qbds.fields().addField(fieldNum(ITMCreatorSetupTable, TableNum));
            qbds.fields().addField(fieldNum(ITMCreatorSetupTable, FieldNum));

            switch (_transType)
            {
                case InventTransType::Sales:
                    salesLine = SalesLine::findInventTransId(_inventTransId);
                    dataAreaId = salesLine.dataAreaId;
                    keyStr = salesLine.dataAreaId;

                    qbds.addRange(fieldNum(ITMCreatorSetupTable, tableNum)).value(queryValue(tableNum(SalesTable)));
                    qbds.addRange(fieldNum(ITMCreatorSetupTable, tableNum)).value(queryValue(tableNum(SalesLine)));
                    qbds.addRange(fieldNum(ITMCreatorSetupTable, tableNum)).value(queryValue(tableNum(InventDim)));

                    queryRun = new QueryRun(query);

                    while (queryRun.next())
                    {
                        shipCreatorSetupTable = queryRun.get(tableNum(ITMCreatorSetupTable));

                        switch (shipCreatorSetupTable.TableNum)
                        {
                            case tableNum(SalesTable):
                                if (!salesTable)
                                {
                                    salesTable = salesLine.salesTable();
                                }
                                keyStr += salesTable.(shipCreatorSetupTable.FieldNum);
                                break;

                            case tableNum(SalesLine):
                                keyStr += salesLine.(shipCreatorSetupTable.FieldNum);
                                break;

                            case tableNum(InventDim):
                                if (!inventDim)
                                {
                                    inventDim = salesLine.inventDim();
                                }
                                keyStr += inventDim.(shipCreatorSetupTable.FieldNum);
                                break;
                        }
                    }
                    break;

                case InventTransType::TransferOrderShip:
                    inventTransferLine = InventTransferLine::findTransIdShip(_inventTransId);
                    dataAreaId = inventTransferLine.dataAreaId;
                    keyStr = inventTransferLine.dataAreaId;

                    qbds.addRange(fieldNum(ITMCreatorSetupTable, tableNum)).value(queryValue(tableNum(InventTransferTable)));
                    qbds.addRange(fieldNum(ITMCreatorSetupTable, tableNum)).value(queryValue(tableNum(InventTransferLine)));
                    qbds.addRange(fieldNum(ITMCreatorSetupTable, tableNum)).value(queryValue(tableNum(InventDim)));

                    queryRun = new QueryRun(query);

                    while (queryRun.next())
                    {
                        shipCreatorSetupTable = queryRun.get(tableNum(ITMCreatorSetupTable));

                        switch (shipCreatorSetupTable.TableNum)
                        {
                            case tableNum(InventTransferTable):
                                if (!inventTransferTable)
                                {
                                    inventTransferTable = inventTransferLine.inventTransferTable();
                                }
                                keyStr += inventTransferTable.(shipCreatorSetupTable.FieldNum);
                                break;

                            case tableNum(InventTransferLine):
                                keyStr += inventTransferLine.(shipCreatorSetupTable.FieldNum);
                                break;

                            case tableNum(InventDim):
                                if (!inventDim)
                                {
                                    inventDim = inventTransferLine.inventDim();
                                }
                                keyStr += inventDim.(shipCreatorSetupTable.FieldNum);
                                break;
                        }
                    }
                    break;
                }
        }
        else
        {
            dataAreaId = curExt();
            keyStr = dataAreaId;
        }

        mapKey = [_transType, keyStr];

        if (companyFolioMap.exists(mapKey))
        {
            shipFolioId = companyFolioMap.lookup(mapKey);
        }
        else
        {
            shipFolioTable.clear();
            shipFolioTable.initValue();
            shipFolioTable.initFromShipTable(shipTable);
            shipFolioTable.ShipId = shipTable.ShipId;
            shipFolioTable.ShipFolioId = manualFolioId != '' ? manualFolioId : NumberSeq::newGetNum(ITMParameters::numRefShipFolioIdOutETG(), false).num();
            shipFolioTable.ShipCustomsBroker = customsBroker;
            shipFolioTable.VendAccount = vendAccount;
            shipFolioTable.ShipDataArea = dataAreaId;
            shipFolioId = shipFolioTable.ShipFolioId;

            companyFolioMap.insert(mapKey, shipFolioId);

            if (shipFolioTable.validateWrite())
            {
                shipFolioTable.insert();
            }
            else
            {
                throw error("@SYS18447");
            }
        }
    }

    return shipFolioId;
}

