protected void initTmpShipCreatorLine()
{
    MapEnumerator   mE = Map::create(selectedLinesMap).getEnumerator();
    PurchLine       purchLine;

    while (mE.moveNext())
    {
        select firstOnly crossCompany dataAreaId, InventTransId from purchLine
            where purchLine.RecId == mE.currentKey();

        tmpShipCreatorLine.clear();
        tmpShipCreatorLine.ShipDataArea = purchLine.dataAreaId;
        tmpShipCreatorLine.InventTransId = purchLine.InventTransId;
        tmpShipCreatorLine.TransferQty = mE.currentValue();
        tmpShipCreatorLine.Selected = NoYes::Yes;
        tmpShipCreatorLine.insert();
    }
}

