protected boolean prompt()
{
    boolean         ret = false;

    if (this.validate(true))
    {
        boolean isITMEnabled = ITMFeatureManagementVisibilityManager::isEnabled();
        createContainer = isITMEnabled && !addToExistingContainer;
        createFolio = isITMEnabled && !addToExistingFolio;
        findAutoCosts = NoYes::Yes;

        ret = true;
    }

    return ret;
}

protected void preRunValidation()
{
    if (!this.validate())
    {
        throw error("@SYS18447");
    }

    if (findAutoCosts && shipId)
    {
        this.checkExistingAutoCosts();
    }
}

protected void preRunOperation()
{
}

protected void postShipLineCreation()
{
}

protected void postRunOperation()
{
    if (pendingShipment && pendingContainer)
    {
        ITMContainers pendingShipContainers = ITMContainers::find(pendingShipment, pendingContainer, true);
        pendingShipContainers.ShipPendingUsed = NoYes::Yes;
        pendingShipContainers.update();
    }

    if (findAutoCosts)
    {
        this.findAutoCosts();
    }

    if (shipContainers && createContainer && !addToExistingContainer)
    {
        this.updateContainerShipDate();
    }
}

protected boolean postRunValidation(int _numOfLines)
{
    boolean ret;
    if (!_numOfLines)
    {
        throw error("@InboundTransportationManagement:AShipmentHasNotBeenCreatedAsNoLinesCould");
    }

    if (shipId)
    {
        info(strFmt("@InboundTransportationManagement:RecordsAddedToShipmentValue", shipTable.ShipId), '', SysInfoAction_TableField::newBuffer(shipTable));
        ret = true;
    }
    else if (shipTable.RecId)
    {
        info(strFmt("@InboundTransportationManagement:ShipmentValueCreatedDot", shipTable.ShipId), '', SysInfoAction_TableField::newBuffer(shipTable));
        ret = true;
    }
    return ret;
}

protected boolean run()
{
    using (var activityContext = ITMInstrumentationLogger::newFromName(classStr(ETGITMCreatorCreateShipmentOut)).getActivities().getCreateShipment())
    {
        ITMTmpCreatorLine tmpShipCreatorLineLocal;
        Counter numOfLines;
        ITMContainers pendingShipContainers;
        boolean ret;

        setPrefix("@InboundTransportationManagement:ShipmentCreator");

        this.preRunValidation();
        this.preRunOperation();

        ttsBegin;

        tmpShipCreatorLineLocal.setTmpData(tmpShipCreatorLine);
        companyFolioMap = new Map(Types::Container, Types::String);

        ITMTTSTable::createTTSOutETG();

        while select sum(TransferQty), sum(InventQty), InventTransId, Close, ShipDataArea, InventTransType from tmpShipCreatorLineLocal
            group by InventTransId, Close, ShipDataArea, InventTransType
            where tmpShipCreatorLineLocal.Selected == NoYes::Yes
                && tmpShipCreatorLineLocal.AddedToBucket == NoYes::Yes
                && tmpShipCreatorLineLocal.TransferQty >  0
        {
            if (!headersCreated)
            {
                this.createHeaders();
            }

            changeCompany (tmpShipCreatorLineLocal.ShipDataArea)
            {
                numOfLines += this.createShipLine(tmpShipCreatorLineLocal);
            }
        }

        this.postShipLineCreation();

        ITMTTSTable::deleteTTSOutETG();

        ret = this.postRunValidation(numOfLines);
        this.postRunOperation();

        ttsCommit;

        return ret;
    }
}

public boolean unpack(container _packedClass)
{
    Version version = RunBase::getVersion(_packedClass);
    boolean ret;

    switch (version)
    {
        case CurrentVersion:
            [version, #CurrentList] = _packedClass;
            ret = true;
            break;

        default:
            ret = false;
    }

    return ret;
}

private void updateContainerShipDate()
{
    ITMContainers shipContainersLocal;

    shipContainersLocal = ITMContainers::findRecId(shipContainers.RecId, true);
    shipContainersLocal.ShipDate = shipDate;
    shipContainersLocal.update();
}

protected boolean validate(boolean _prePromptCheck = false)
{
    boolean ret = true;

    if (!shipId && !vesselId)
    {
        ret = checkFailed("@InboundTransportationManagement:VesselMustBeSpecifiedDot");
    }

    if (((createContainer && !_prePromptCheck) || addToExistingContainer) && !containerId)
    {
        ret = checkFailed("@InboundTransportationManagement:ContainerMustBeSpecifiedDot");
    }

    if (addToExistingFolio && !folioId)
    {
        ret = checkFailed("@InboundTransportationManagement:FolioMustBeSpecifiedDot");
    }

    if (this.parmContainerTypeId())
    {
        Weight weight, maxWeight;
        Volume volume, maxVolume;
        InventQty qty;
        NoYes volumeMissing, weightMissing;
        NoYes outsideWeightTolerance, outsideVolumeTolerance;
        ITMTmpCreatorLine tmpShipCreatorLineCheck;
        tmpShipCreatorLineCheck.setTmpData(tmpShipCreatorLine);

        [weight,
         volume,
         qty,
         volumeMissing,
         weightMissing,
         maxWeight,
         maxVolume,
         outsideWeightTolerance,
         outsideVolumeTolerance] = ETGITMCreatorTableGeneration::selectedTotals(tmpShipCreatorLineCheck, this.parmContainerTypeId());

        if (outsideWeightTolerance)
        {
            ret = checkFailed(strFmt("@InboundTransportationManagement:OutOfWeightTolerance", this.parmContainerTypeId()));
        }

        if (outsideVolumeTolerance)
        {
            ret = checkFailed(strFmt("@InboundTransportationManagement:OutOfVolumeTolerance", this.parmContainerTypeId()));
        }
    }

    return ret;
}

protected void initFromContract(ITMCreatorCreateShipmentContract _contract)
{
    tmpShipCreatorLine.setTmpData(_contract.parmTmpShipCreatorLine());
    shipJourneyLine.setTmpData(_contract.parmShipJourneyLine());

    vesselId                    = _contract.parmVesselId();
    fromPort                    = _contract.parmFromPort();
    toPort                      = _contract.parmToPort();
    dlvModeId                   = _contract.parmDlvModeId();
    shipVendAccount             = _contract.parmShipVendAccount();
    containerId                 = _contract.parmContainerId();
    containerTypeId             = _contract.parmContainerTypeId();
    customsBroker               = _contract.parmCustomsBroker();
    vendAccount                 = _contract.parmVendAccount();
    journeyId                   = _contract.parmJourneyId();
    pendingShipment             = _contract.parmPendingShipment();
    pendingContainer            = _contract.parmPendingContainer();
    shipDescription             = _contract.parmShipDescription();
    shipId                      = _contract.parmShipId();
    voyage                      = _contract.parmVoyage();
    containerJourneyId          = _contract.parmContainerJourneyId();
    addToExistingContainer      = _contract.parmAddToExistingContainer();
    addToExistingFolio          = _contract.parmAddToExistingFolio();
    folioId                     = _contract.parmFolioId();
    shipDate                    = _contract.parmShipDate();
    shipMAWB                    = _contract.parmShipMAWB();
    shipHAWB                    = _contract.parmShipHAWB();
    containerMeasurement        = _contract.parmContainerMeasurement();
    containerMeasurementUnit    = _contract.parmContainerMeasurementUnit();
    shipIdExternal              = _contract.parmShipIdExternal();
    manualFolioId               = _contract.parmManualFolioId();
    selectedLinesMap            = _contract.parmSelectedLinesMap();
}

public static ETGITMCreatorCreateShipmentOut construct()
{
    if(FeatureStateProvider::isFeatureEnabled(ETGOTMCreateShipmentForSameCompanyFeature::instance()))
    {
        return new ETGITMCreatorCreateShipmentWithinSameCompanyOut();
    }
    else
    {
        return new ETGITMCreatorCreateShipmentOut();
    }
}

