    shipCreatorCreateShipment.parmVendAccount(_itmContainers.ShipLocalForwarder);
    shipCreatorCreateShipment.parmJourneyId(_itmContainers.ShipJourneyId);
    shipCreatorCreateShipment.parmShipDescription(_itmTable.ShipDescription);
    shipCreatorCreateShipment.parmShipId(_itmTable.ShipId);
